custom_fields.gauge:
[[[
  var n = variables.num, pfx = variables.prefix, ch = variables.chan || 'food_1';
  var eProbe  = pfx + '_probe_' + n + '_' + ch + '_temperature';
  var eBatt   = pfx + '_probe_' + n + '_battery';
  var eTarget = 'input_number.inkbird_target_' + n;
  var eName   = 'input_text.inkbird_name_' + n;
  var eState  = 'sensor.bbq_probe_' + n + '_status';
  var eRate   = 'sensor.bbq_probe_' + n + '_rate';
  var _g = function(e){ var o = states[e]; return o ? o.state : undefined; };
  var s = _g(eState) || 'idle';
  var col = s==='ready' ? '#56c271' : s==='close' ? '#ff6a2c' : s==='heating' ? '#f2b441' : '#77695c';
  var t = parseFloat(_g(eProbe));
  var g = parseFloat(_g(eTarget));
  var amb = 22, connected = !isNaN(t);
  var pct = connected ? Math.max(0, Math.min(1,(t-amb)/(g-amb))) : 0;
  var R=52, C=2*Math.PI*R, ARC=0.75;
  var dash=(C*ARC*pct).toFixed(1)+' '+C;
  var uf = (_g('input_select.inkbird_unit')||'').indexOf('F') >= 0;
  var us = uf ? '\u00b0F' : '\u00b0C';
  var cv = function(c){ return uf ? Math.round(c*9/5+32) : Math.round(c*10)/10; };
  var temp = connected ? cv(t) : '\u2014';
  return `<div style="position:relative;width:128px;height:128px;margin:auto">
    <svg width="128" height="128" viewBox="0 0 128 128" style="transform:rotate(135deg)">
      <circle cx="64" cy="64" r="${R}" fill="none" stroke="#33291f" stroke-width="9"
        stroke-linecap="round" stroke-dasharray="${(C*ARC).toFixed(1)} ${C}"/>
      <circle cx="64" cy="64" r="${R}" fill="none" stroke="${col}" stroke-width="9"
        stroke-linecap="round" stroke-dasharray="${dash}"
        style="transition:stroke-dasharray .6s ease,stroke .4s"/>
    </svg>
    <div style="position:absolute;inset:0;display:flex;flex-direction:column;
         align-items:center;justify-content:center;font-family:ui-monospace,monospace">
      <div style="font-size:1.7rem;font-weight:650;color:#f5ede4;line-height:1">${temp}<span style="font-size:.9rem;color:#a89a8c">${us}</span></div>
      <div style="font-size:.72rem;color:#77695c;margin-top:2px">${connected?'target '+cv(g)+'\u00b0':'no probe'}</div>
    </div>
  </div>`;
]]]

custom_fields.side:
[[[
  var n = variables.num, pfx = variables.prefix, ch = variables.chan || 'food_1';
  var eProbe  = pfx + '_probe_' + n + '_' + ch + '_temperature';
  var eBatt   = pfx + '_probe_' + n + '_battery';
  var eTarget = 'input_number.inkbird_target_' + n;
  var eName   = 'input_text.inkbird_name_' + n;
  var eState  = 'sensor.bbq_probe_' + n + '_status';
  var eRate   = 'sensor.bbq_probe_' + n + '_rate';
  var _g = function(e){ var o = states[e]; return o ? o.state : undefined; };
  var s = _g(eState) || 'idle';
  var col = s==='ready' ? '#56c271' : s==='close' ? '#ff6a2c' : s==='heating' ? '#f2b441' : '#77695c';
  var t = parseFloat(_g(eProbe));
  var g = parseFloat(_g(eTarget));
  var connected = !isNaN(t);
  var uf = (_g('input_select.inkbird_unit')||'').indexOf('F') >= 0;
  var us = uf ? '\u00b0F' : '\u00b0C';
  var cv = function(c){ return uf ? Math.round(c*9/5+32) : Math.round(c*10)/10; };
  var togo = uf ? Math.round((g-t)*9/5) : Math.round((g-t)*10)/10;
  var footer = !connected ? 'Insert a probe to begin'
    : (s==='ready' ? 'Reached target \u2014 resting'
    : Math.max(0, togo) + '\u00b0 to go');
  // ETA from the derivative sensor (\u00b0C/h). Only meaningful while actually
  // climbing — a flat or falling probe would give a nonsense or negative time.
  var rate = parseFloat(_g(eRate));
  var eta = '';
  if (connected && s !== 'ready' && !isNaN(rate) && rate > 0.5 && g > t) {
    var mins = Math.round((g - t) / rate * 60);
    if (mins > 0 && mins <= 1440) {
      var hh = Math.floor(mins/60), mm = mins % 60;
      eta = hh ? ('\u2248 ' + hh + ' h ' + mm + ' m') : ('\u2248 ' + mm + ' m');
    }
  }
  return `<div style="display:flex;flex-direction:column;gap:9px;font-family:system-ui">
    <div style="display:flex;align-items:center;gap:10px">
      <span style="flex:1;font-size:.72rem;text-transform:uppercase;letter-spacing:.12em;color:#77695c">Target</span>
      <span style="font-family:ui-monospace,monospace;font-weight:600;font-size:1.05rem;color:#f5ede4">${cv(g)}${us}</span>
    </div>
    <div style="font-size:.78rem;color:#a89a8c">${footer}</div>
    ${eta ? `<div style="font-family:ui-monospace,monospace;font-size:.74rem;color:${col}">${eta}</div>` : ''}
  </div>`;
]]]

custom_fields.t:
[[[
  var u = states['input_select.inkbird_unit'];
  var uf = u ? u.state.indexOf('F') >= 0 : false;
  var v = uf ? Math.round(variables.temp * 9/5 + 32) : variables.temp;
  var us = uf ? '\u00b0F' : '\u00b0C';
  return `<div style="font-family:ui-monospace,monospace;font-weight:650;font-size:1.15rem;color:#ff6a2c">${v}<span style="font-size:.74rem;color:#a89a8c">${us}</span></div>`;
]]]

