custom_fields.status:
[[[
  var tr = states['sensor.inkbird_int_14_active_transport'];
  var bc = states['binary_sensor.inkbird_int_14_ble_connected'];
  var t  = tr ? tr.state : 'unknown';
  var map = {
    ble:        ['Bluetooth', 'live'],
    ble_waiting:['Bluetooth', 'wait'],
    wifi:       ['Wi-Fi',     'live'],
    wi_fi:      ['Wi-Fi',     'live'],
    local_lan:  ['LAN',       'live'],
    lan:        ['LAN',       'live'],
    cloud:      ['Cloud',     'live'],
    none:       ['no link',   'down'],
    unknown:    ['no link',   'down'],
    unavailable:['no link',   'down']
  };
  var m = map[t] || [t.replace(/_/g,' '), 'live'];
  var how = m[0], mode = m[1];
  if (mode === 'live' && t.indexOf('ble') === 0 && !(bc && bc.state === 'on')) mode = 'wait';
  var col  = mode === 'live' ? '#56c271' : mode === 'wait' ? '#f2b441' : '#e8503a';
  var word = mode === 'live' ? 'Live'    : mode === 'wait' ? 'Connecting' : 'Offline';
  var pulse = mode === 'wait' ? 'animation:inkbird-pulse 1.4s ease-in-out infinite' : '';
  var b = states['sensor.overig_inkbird_int_14_base_battery'].state;
  b = (b === undefined || b === 'unknown' || b === 'unavailable') ? '\u2014' : b + '%';
  return `<style>@keyframes inkbird-pulse{0%,100%{opacity:1}50%{opacity:.25}}</style>
  <div style="display:flex;gap:10px;align-items:center;font-family:system-ui">
    <span title="active transport: ${t}"
      style="display:inline-flex;align-items:center;gap:8px;background:#211b16;
      border:1px solid #3a2f27;padding:8px 13px;border-radius:999px;font-size:.82rem;color:#a89a8c">
      <span style="width:8px;height:8px;border-radius:50%;background:${col};${pulse}"></span>
      ${word} \u00b7 <b style="color:#f5ede4">${how}</b></span>
    <span style="background:#211b16;border:1px solid #3a2f27;padding:8px 13px;
      border-radius:999px;font-size:.82rem;color:#a89a8c">Base battery
      <b style="color:#f5ede4">${b}</b></span>
  </div>`;
]]]

cards.content:
{% set ns = namespace(rows=[]) %}
{% for i in range(1,5) %}
  {% set s = states('sensor.bbq_probe_' ~ i ~ '_status') %}
  {% set n = states('input_text.inkbird_name_' ~ i) %}
  {% set g = states('input_number.inkbird_target_' ~ i) | int %}
  {% if s == 'ready' %}
    {% set ns.rows = ns.rows + ['🟢 **' ~ n ~ '** reached ' ~ g ~ '°C — ready'] %}
  {% elif s == 'close' %}
    {% set ns.rows = ns.rows + ['🟡 **' ~ n ~ '** almost there (target ' ~ g ~ '°C)'] %}
  {% endif %}
{% endfor %}
### Alerts
{% if ns.rows | length == 0 %}
_No alerts. Everything's on track._
{% else %}
{% for r in ns.rows %}- {{ r }}
{% endfor %}
{% endif %}

