custom_fields.batt:
[[[
  var raw = parseInt(states['sensor.overig_inkbird_int_14_base_battery'].state);
  var pct = isNaN(raw) ? 0 : raw;
  var col = pct < 20 ? '#e8503a' : '#56c271';
  return `<div style="display:flex;align-items:center;gap:9px">
    <div style="width:40px;height:18px;border:2px solid #a89a8c;border-radius:4px;padding:2px;position:relative">
      <div style="height:100%;width:${pct}%;background:${col};border-radius:1px"></div></div>
    <span style="font-family:ui-monospace,monospace;font-weight:600;color:#f5ede4">${isNaN(raw)?'—':pct+'%'}</span>
  </div>`;
]]]

